class Solution:
    def zigZagArrays(self, n, l, r):
        MOD = 10**9 + 7
        vals = list(range(l, r + 1))
        count = [0]
        def rec(seq):
            if len(seq) == n:
                count[0] += 1
                return
            for v in vals:
                if seq:
                    if v == seq[-1]:
                        continue
                    if len(seq) >= 2:
                        a, b = seq[-2], seq[-1]
                        if a < b < v or a > b > v:
                            continue
                seq.append(v)
                rec(seq)
                seq.pop()
        rec([])
        return count[0] % MOD

