class Solution:
    def zigZagArrays(self, n, l, r):
        MOD = 10**9 + 7
        m = r - l + 1
        up = [1] * m
        down = [1] * m
        for _ in range(n - 1):
            pref_down = [0] * (m + 1)
            for i in range(m):
                pref_down[i + 1] = (pref_down[i] + down[i]) % MOD
            suf_up = [0] * (m + 1)
            for i in range(m - 1, -1, -1):
                suf_up[i] = (suf_up[i + 1] + up[i]) % MOD
            new_up = [0] * m
            new_down = [0] * m
            for i in range(m):
                new_up[i] = pref_down[i]
                new_down[i] = suf_up[i + 1]
            up, down = new_up, new_down
        total = 0
        for i in range(m):
            total = (total + up[i] + down[i]) % MOD
        return total

