var zigZagArrays = function(n, l, r) {
    const MOD = 1000000007n;
    const m = r - l + 1;
    let up = new Array(m).fill(1n);
    let down = new Array(m).fill(1n);
    for (let step = 0; step < n - 1; step++) {
        const prefDown = new Array(m + 1).fill(0n);
        for (let i = 0; i < m; i++) prefDown[i + 1] = (prefDown[i] + down[i]) % MOD;
        const sufUp = new Array(m + 1).fill(0n);
        for (let i = m - 1; i >= 0; i--) sufUp[i] = (sufUp[i + 1] + up[i]) % MOD;
        const newUp = new Array(m).fill(0n);
        const newDown = new Array(m).fill(0n);
        for (let i = 0; i < m; i++) { newUp[i] = prefDown[i]; newDown[i] = sufUp[i + 1]; }
        up = newUp; down = newDown;
    }
    let total = 0n;
    for (let i = 0; i < m; i++) total = (total + up[i] + down[i]) % MOD;
    return Number(total);
};
